package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.Paths

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serveFile(filePath: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    val baseDir = Paths.get("uploads").toAbsolutePath.normalize
    val requestedFile = baseDir.resolve(filePath).normalize

    if (!requestedFile.startsWith(baseDir)) {
      Forbidden("Access denied")
    } else {
      val file = new File(requestedFile.toString)
      if (file.exists && file.isFile) {
        val source = Source.fromFile(file)
        try {
          Ok(source.mkString).as("application/octet-stream")
        } catch {
          case _: Exception => InternalServerError("Error reading file")
        } finally {
          source.close()
        }
      } else {
        NotFound("File not found")
      }
    }
  }
}